/* --- CSS Isolation & Bounding Box --- */
#resume {
  /* --- Core Variables (Defaults) --- */
  --primary-text-color: #2D2D2D;
  --secondary-text-color: #6B6B6B;
  --divider-color: #E0E0E0;
  --accent-color: #005A5A;

  /* --- Typography Variables --- */
  --font-family-body: 'Lato', sans-serif;
  --font-family-heading: 'Lato', sans-serif;
  --font-size-base: 11pt;
  --font-size-name: 22pt;
  --font-size-section-title: 15pt;
  --font-size-entry-title: 12pt;
  --font-size-meta: 11pt;

  /* --- Spacing System (Based on Cheatsheet) --- */
  --base-line-height: calc(var(--font-size-base) * 1.4);
  --space-bullet-list: calc(var(--base-line-height) * 0.35 * var(--rt-spacing));
  --space-entry-header: calc(var(--base-line-height) * 0.25 * var(--rt-spacing));
  --space-entry-content-top: calc(var(--base-line-height) * 0.4 * var(--rt-spacing));
  --space-between-entries: calc(var(--base-line-height) * 1.25 * var(--rt-spacing));
  --space-after-section-title: calc(var(--base-line-height) * 1.0 * var(--rt-spacing));
  --space-between-sections: calc(var(--base-line-height) * 1.25 * var(--rt-spacing));
  --page-margin: calc(var(--base-line-height) * 4.0 * var(--rt-spacing));

  /* --- Document Setup --- */
  background-color: #fff;
  color: var(--primary-text-color);
  font-family: var(--font-family-body);
  font-size: var(--font-size-base);
  line-height: 1.4;
  width: 210mm;
  min-height: 297mm;
  box-sizing: border-box;
  padding: var(--page-margin);
}

/* --- Global Element Styles (Scoped) --- */
#resume a {
  color: var(--secondary-text-color);
  text-decoration: none;
}
#resume a:hover {
  color: var(--accent-color);
  text-decoration: underline;
}
#resume h1, #resume h2, #resume h3, #resume p, #resume ul, #resume li {
  margin: 0;
  padding: 0;
}

/* --- Layout & Sections (Scoped) --- */
#resume .rt-section {
  margin-bottom: var(--space-between-sections);
}
#resume .rt-section:last-of-type {
  margin-bottom: 0;
}
#resume .rt-section-title {
  font-family: var(--font-family-heading);
  font-size: var(--font-size-section-title);
  color: var(--primary-text-color);
  margin-bottom: var(--space-after-section-title);
}

/* --- Reusable Entry Component (Scoped) --- */
#resume .rt-entry {
  margin-bottom: var(--space-between-entries);
}
#resume .rt-entry:last-of-type {
  margin-bottom: 0;
}
#resume .rt-entry-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: var(--space-entry-header);
}
#resume .rt-entry-title {
  font-family: var(--font-family-heading);
  font-size: var(--font-size-entry-title);
  font-weight: 700;
}
#resume .rt-entry-subtitle {
  font-family: var(--font-family-heading);
  font-size: var(--font-size-entry-title);
  font-weight: 400; 
  margin-top: 2px;
}
#resume .rt-entry-meta {
  text-align: right;
  color: var(--secondary-text-color);
  font-size: var(--font-size-meta);
  white-space: nowrap;
  flex-shrink: 0;
  padding-left: 1em;
}
#resume .rt-entry-description {
  margin-top: var(--space-entry-content-top);
}
#resume .rt-entry-description ul {
  padding-left: 1.5em;
  list-style-type: disc;
}
#resume .rt-entry-description li {
  margin-bottom: var(--space-bullet-list);
}
#resume .rt-entry-description li:last-child {
  margin-bottom: 0;
}

#resume .rt-simple-list {
  list-style: none;
  padding: 0;
  display: flex;
  flex-wrap: wrap;
  gap: 0.5em 1.5em; 
}

#resume .rt-simple-list span {
  color: var(--secondary-text-color);
}
@media print {
  @page {
    margin-top: 0.50in; 
  }
  @page :first {
    margin-top: 0;
  }
  .rt-section ul > li, 
  .rt-entry {
    break-inside: avoid;
  }
  .rt-section-title {
    break-after: avoid;
  }
}

sections.html:
{{#if content.education}}
<section class="rt-section">
    <h2 class="rt-section-title">Education</h2>
    {{#each content.education}}
    <div class="rt-entry">
        <div class="rt-entry-header">
            <div>
                <h3 class="rt-entry-title">{{this.qualification}}</h3>
                <p class="rt-entry-subtitle">{{this.institution}}{{#if this.honorsOrMinor}} | {{this.honorsOrMinor}}{{/if}}</p>
            </div>
            <div class="rt-entry-meta">
                {{#if this.gpa}}<span>{{this.gpa}}</span><br>{{/if}}
                <span>{{this.dates}}</span>
            </div>
        </div>
        {{#if this.description}}
        <div class="rt-entry-description">
            {{{formatAsList this.description}}}
        </div>
        {{/if}}
    </div>
    {{/each}}
</section>
{{/if}}

{{#if content.projects}}
<section class="rt-section">
  <h2 class="rt-section-title">Projects</h2>
  {{#each content.projects}}
  <div class="rt-entry">
    <div class="rt-entry-header">
      <div>
        <h3 class="rt-entry-title">{{this.projectName}}</h3>
        {{! --- This is the corrected block --- }}
        {{#if this.role}}
            <p class="rt-entry-subtitle">{{this.role}}{{#if this.techStack}} | {{this.techStack}}{{/if}}</p>
        {{else}}
            {{#if this.techStack}}
                <p class="rt-entry-subtitle">{{this.techStack}}</p>
            {{/if}}
        {{/if}}
      </div>
      {{#if this.links}}
      <div class="rt-entry-meta">
        {{#each this.links}}
          <a href="{{sanitizeUrl this.url}}" target="_blank" rel="noopener noreferrer">{{this.text}}</a>{{#unless @last}} | {{/unless}}
        {{/each}}
      </div>
      {{/if}}
    </div>
    <div class="rt-entry-description">
      {{{formatAsList this.description}}}
    </div>
  </div>
  {{/each}}
</section>
{{/if}}

{{#if content.certifications}}
<section class="rt-section">
    <h2 class="rt-section-title">Certifications & Licenses</h2>

    {{#each content.certifications}}
    <div class="rt-entry">
        <div class="rt-entry-header">
