                {{#if this.verificationLink}}
                    <br><a href="{{sanitizeUrl this.verificationLink}}" target="_blank" rel="noopener noreferrer">Verify Credential</a>
                {{/if}}
            </div>
        </div>
    </div>
    {{/each}}
</section>
{{/if}}

