{{#if content.publications}}
<section class="rt-section">
    <h2 class="rt-section-title">Publications</h2>

    {{#each content.publications}}
    <div class="rt-entry">
        {{! The main title, which is a link if a URL is provided }}
        <h3 class="rt-entry-title">
            {{#if this.url}}
                <a href="{{sanitizeUrl this.url}}" target="_blank" rel="noopener noreferrer">{{this.title}}</a>
            {{else}}
                {{this.title}}
            {{/if}}
        </h3>
        {{! The list of authors }}
        <p class="rt-entry-subtitle">{{this.authors}}</p>

        <div class="rt-entry-description">
            {{! This block formats the citation details like a professional journal entry }}
            <p class="rt-publication-meta">
                <em>{{this.journal}}</em>{{#if this.volume}}, <strong>{{this.volume}}</strong>{{/if}}{{#if this.issue}}({{this.issue}}){{/if}}{{#if this.pages}}, pp. {{this.pages}}{{/if}}. ({{this.date}}).
            </p>

            {{! The optional summary of the work }}
            {{#if this.summary}}
                <p class="rt-publication-summary">{{{this.summary}}}</p>
            {{/if}}
        </div>
    </div>
    {{/each}}
</section>
{{/if}}

