        </div>

        {{#if this.description}}
        <div class="rt-entry-description">
            <p>{{{this.description}}}</p>
        </div>
        {{/if}}
    </div>
    {{/each}}

</section>
{{/if}}

{{#if content.licensure}}
<section class="rt-section">
    <h2 class="rt-section-title">Licensure</h2>

    {{#each content.licensure}}
    <div class="rt-entry">
        <div class="rt-entry-header">
            <div>
                <h3 class="rt-entry-title">{{this.licenseName}}</h3>
                <p class="rt-entry-subtitle">{{this.issuingBody}}</p>
            </div>
            <div class="rt-entry-meta">
                {{#if this.licenseNumber}}
