/* --- Corporate Authority (Helvetica/Garamond) --- */
@import url('https://fonts.googleapis.com/css2?family=Garamond:ital@0;1&display=swap');
/* Note: Helvetica Neue is a system font and does not require an import */

/* --- 1. Variable Definitions from Cheatsheet --- */
#resume {
  --accent-color: #003366; /* Navy */
  --font-family-body: 'Garamond', serif;
  --font-family-heading: 'Helvetica Neue', sans-serif;
  --font-size-name: 24pt;
  --font-size-section-title: 16pt;
  --font-size-entry-title: 12pt; /* Corresponds to "Subheadings" */
  --font-size-base: 12pt;      /* Corresponds to "Body Text" */
  --font-size-meta: 12pt;      /* Corresponds to "Dates/Location" */
}

/* --- 2. Layout and Thematic Styles --- */
#resume .rt-header {
  text-align: left;
  border-bottom: 2px solid var(--accent-color);
  padding-bottom: var(--space-entry-content-top);
  margin-bottom: var(--space-between-sections);
}

#resume .rt-contact-info {
  font-family: var(--font-family-body); /* Use body font for contact details */
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-start; /* Left-aligned */
  gap: 0.75em;
  margin-top: var(--space-entry-content-top);
}

#resume .rt-contact-info span:not(:last-child)::after {
  content: '|';
  margin-left: 0.75em;
  color: var(--divider-color);
}

/* --- 3. Detailed Typographic Rules --- */

/* Your Name */
#resume .rt-name {
  font-family: var(--font-family-heading);
  font-size: var(--font-size-name);
  font-weight: 700; /* Bold */
  color: var(--accent-color);
  margin: 0;
}

/* Professional Title */
#resume .rt-title {
  font-family: var(--font-family-heading);
  font-size: 14pt;
  font-weight: 400; /* Regular */
  color: var(--primary-text-color);
  margin: 4px 0 8px 0;
}

/* Section Headings: e.g., "Work Experience" */
#resume .rt-section-title {
  font-family: var(--font-family-heading);
  font-size: var(--font-size-section-title);
  font-weight: 700; /* Bold */
  color: var(--primary-text-color);
  text-transform: none; /* Not uppercase for a more traditional feel */
  border-bottom: 1px solid var(--divider-color);
  padding-bottom: calc(var(--base-line-height) * 0.2);
  margin-bottom: var(--space-after-section-title);
}

/* Subheadings: e.g., "Senior Software Engineer" */
#resume .rt-entry-title {
  font-family: var(--font-family-heading);
  font-size: var(--font-size-entry-title);
  font-weight: 700; /* Bold */
  color: var(--primary-text-color);
  margin: 0;
}

/* Sub-Subheadings: e.g., "Company Name" */
#resume .rt-entry-subtitle {
  font-family: var(--font-family-heading);
  font-size: var(--font-size-entry-title); /* Same size as title */
  font-weight: 400; /* Regular weight for contrast */
  color: var(--primary-text-color);
  margin: 2px 0 0 0;
}

/* Meta Info: e.g., "Jan 2022" */
#resume .rt-entry-meta {
  font-family: var(--font-family-body);
  font-size: var(--font-size-meta);
  font-weight: 400; /* Regular */
  color: var(--secondary-text-color);
  font-style: italic; /* Italic as per cheatsheet */
}

/* Skills Section Specifics */
#resume .rt-skills-list {
  list-style: none;
  padding: 0;
  font-family: var(--font-family-body); /* Ensure skills use the body font */
}

#resume .rt-skills-list li {
  margin-bottom: calc(var(--space-bullet-list) * 0.5);
}

#resume .rt-skills-list strong {
  font-family: var(--font-family-heading); /* Use heading font for categories */
  font-weight: 700;
  margin-right: 0.5em;
}

